// 读取当前文档内容并分析结构
var doc = Application.ActiveDocument;
var content = "";
var paragraphs = [];

for (var i = 1; i <= doc.Paragraphs.Count; i++) {
    var para = doc.Paragraphs.Item(i);
    var text = para.Range.Text;
    content += text;
    paragraphs.push({
        index: i,
        text: text,
        style: para.Style.NameLocal
    });
}

return {
    totalParagraphs: doc.Paragraphs.Count,
    contentLength: content.length,
    paragraphs: paragraphs.slice(0, 10) // 只返回前10段作为预览
};

// 根据集团公文排版格式要求对文档进行排版
var doc = Application.ActiveDocument;

// 1. 设置页面格式
doc.PageSetup.PaperSize = 9; // A4纸
doc.PageSetup.TopMargin = 37; // 上边距37mm
doc.PageSetup.BottomMargin = 35; // 下边距35mm
doc.PageSetup.LeftMargin = 28; // 左边距28mm
doc.PageSetup.RightMargin = 26; // 右边距26mm

// 2. 设置正文格式
doc.Content.Font.Name = "仿宋_GB2312";
doc.Content.Font.Size = 16; // 三号字
doc.Content.ParagraphFormat.LineSpacingRule = 0; // 单倍行距
doc.Content.ParagraphFormat.FirstLineIndent = 32; // 首行缩进2字符（32磅）

// 3. 设置标题格式
for (var i = 1; i <= doc.Paragraphs.Count; i++) {
    var para = doc.Paragraphs.Item(i);
    var text = para.Range.Text.trim();

    // 一级标题（如"一、强化政治引领，筑牢思想根基"）
    if (/^[一二三四五六七八九十]+、/.test(text)) {
        para.Range.Font.Name = "黑体";
        para.Range.Font.Size = 16; // 三号字
        para.Range.Font.Bold = true;
        para.ParagraphFormat.Alignment = 1; // 居左
        para.ParagraphFormat.FirstLineIndent = 0; // 取消首行缩进
        para.ParagraphFormat.SpaceBefore = 24; // 段前24磅
        para.ParagraphFormat.SpaceAfter = 12; // 段后12磅
    }

    // 二级标题（如"（一）规范基层组织设置"）
    if (/^（[一二三四五六七八九十]+）/.test(text)) {
        para.Range.Font.Name = "楷体_GB2312";
        para.Range.Font.Size = 16; // 三号字
        para.Range.Font.Bold = true;
        para.ParagraphFormat.Alignment = 1; // 居左
        para.ParagraphFormat.FirstLineIndent = 0; // 取消首行缩进
        para.ParagraphFormat.SpaceBefore = 12; // 段前12磅
        para.ParagraphFormat.SpaceAfter = 6; // 段后6磅
    }
}

// 4. 设置主标题（文档标题）
var firstPara = doc.Paragraphs.Item(1);
firstPara.Range.Font.Name = "方正小标宋简体";
firstPara.Range.Font.Size = 22; // 二号字
firstPara.Range.Font.Bold = true;
firstPara.ParagraphFormat.Alignment = 1; // 居左
firstPara.ParagraphFormat.FirstLineIndent = 0;
firstPara.ParagraphFormat.SpaceBefore = 0;
firstPara.ParagraphFormat.SpaceAfter = 24; // 段后24磅

// 5. 设置发文对象
var secondPara = doc.Paragraphs.Item(2);
secondPara.Range.Font.Name = "仿宋_GB2312";
secondPara.Range.Font.Size = 16; // 三号字
secondPara.ParagraphFormat.Alignment = 1; // 居左
secondPara.ParagraphFormat.FirstLineIndent = 0;
secondPara.ParagraphFormat.SpaceBefore = 0;
secondPara.ParagraphFormat.SpaceAfter = 12; // 段后12磅

return "公文排版完成：已设置A4页面、仿宋三号字体、标题格式、行间距等";

